changeSet.sql:
IF OBJECT_ID('dbo.trg_FullGraphDelete', 'TR') IS NOT NULL
DROP TRIGGER dbo.trg_FullGraphDelete;

EXEC('
    CREATE TRIGGER dbo.trg_FullGraphDelete
        ON dbo.graph
        INSTEAD OF DELETE
    AS
    BEGIN

        DELETE FROM dbo.graph_type
        WHERE graph_id IN (SELECT graph_id FROM deleted);

        DELETE e
        FROM dbo.Edges e
        INNER JOIN dbo.Nodes n ON e.source_node_id = n.node_id OR e.target_node_id = n.node_id
        WHERE n.graph_id IN (SELECT graph_id FROM deleted);

        DELETE FROM dbo.Nodes
        WHERE graph_id IN (SELECT graph_id FROM deleted);

        DELETE FROM dbo.graph
        WHERE graph_id IN (SELECT graph_id FROM deleted);

        UPDATE dbo.tables
        SET last_update_at = SYSUTCDATETIME()
        WHERE name = ''graph'';
    END
');
